    fn deduce_quote_style_no_quotes() {
        assert_eq!(
            QuoteStyle::deduce(&mock_cli(vec!["--no-quotes"])),
            QuoteStyle::NoQuotes
        );
    }

    #[test]
    fn deduce_quote_style_quote_spaces() {
        assert_eq!(
            QuoteStyle::deduce(&mock_cli(vec![""])),
            QuoteStyle::QuoteSpaces
        );
    }

